export enum Department {
  TECHNICAL = 'Technical',
  INFRASTRUCTURE = 'Infrastructure',
  ACADEMIC = 'Academic',
  ADMINISTRATIVE = 'Administrative',
  MESS = 'Mess',
  HOSTEL = 'Hostel',
  TRANSPORT = 'Transport',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high',
  CRITICAL = 'critical'
}

export enum Status {
  PENDING = 'pending',
  IN_PROGRESS = 'in-progress',
  RESOLVED = 'resolved',
  CLOSED = 'closed'
}

export enum UserRole {
  STUDENT = 'Student',
  STAFF = 'Staff',
  ADMIN = 'Admin'
}

export interface Attachment {
  name: string;
  type: string;
  data: string; // base64
}

export interface Message {
  id: string;
  senderId: string;
  senderRole: UserRole;
  content: string;
  timestamp: number;
}

export interface GrievanceHistory {
  status: Status;
  timestamp: number;
  userId: string;
  remark?: string;
  reassignedFrom?: Department;
  reassignedTo?: Department;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  department?: Department;
  email: string;
}

export interface Grievance {
  id: string;
  title: string;
  timestamp: number;
  description: string;
  department: Department;
  severity: Severity;
  status: Status;
  isAnonymous: boolean;
  studentId: string;
  assignedToId: string;
  lastStatusChange: number;
  history: GrievanceHistory[];
  remarks: string[];
  attachments?: Attachment[];
  notificationsSent: { type: string; timestamp: number; message: string }[];
  // AI Enhanced fields
  sentiment?: 'Positive' | 'Neutral' | 'Frustrated' | 'Angry' | 'Urgent';
  summary?: string;
  conversation: Message[];
  fingerprint?: string; 
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
  attachments?: Attachment[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeGrievanceState = async (complaintText: string, history: ChatMessage[]) => {
  const historyText = history.map(m => `${m.role}: ${m.content}`).join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `HISTORY:
    ${historyText}

    NEW USER INPUT:
    "${complaintText}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: { type: Type.BOOLEAN },
          followUpQuestion: { type: Type.STRING },
          summary: { type: Type.STRING },
          department: { type: Type.STRING },
          severity: { type: Type.STRING },
          sentiment: { 
            type: Type.STRING, 
            description: "Choose: Positive, Neutral, Frustrated, Angry, Urgent" 
          },
          fingerprint: { type: Type.STRING }
        },
        required: ["isDetailedEnough", "summary", "department", "severity", "sentiment", "fingerprint"],
      },
      systemInstruction: `You are the KIT Redressal Analyst. 
      Analyze the complaint for sentiment (Positive, Neutral, Frustrated, Angry, Urgent).
      If the user is angry or mentions safety, set severity to 'critical'.
      Map departments to: Technical, Infrastructure, Academic, Administrative, Mess, Hostel, Transport.`,
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getStaffAssistance = async (description: string, sentiment: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Complaint: "${description}"
    Detected Sentiment: ${sentiment}`,
    config: {
      systemInstruction: `You are a professional Staff Mediator. 
      The student seems ${sentiment}. Suggest a resolution strategy that addresses this emotion and the technical issue.`,
    },
  });
  return response.text;
};

import { Grievance, User, UserRole, Department, Status, Message } from './types';
import { db } from './db';

let currentUser: User | null = null;
const SESSION_CHANGE_EVENT = 'kit_session_change';

export const setSession = (user: User, token: string) => {
  currentUser = user;
  localStorage.setItem('access_token', token);
  localStorage.setItem('user_profile', JSON.stringify(user));
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
};

export const getCurrentUser = (): User | null => {
  if (currentUser) return currentUser;
  const saved = localStorage.getItem('user_profile');
  if (saved) {
    try {
      currentUser = JSON.parse(saved);
      return currentUser;
    } catch (e) {
      return null;
    }
  }
  return null;
};

export const login = async (userIdOrEmail: string, password: string): Promise<boolean> => {
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  currentUser = null;

  let user = await db.users.findOne({ id: userIdOrEmail, password });
  if (!user) user = await db.users.findOne({ email: userIdOrEmail, password });

  if (user) {
    const { password: _, ...profile } = user;
    setSession(profile as User, 'kit-session-' + Date.now());
    return true;
  }
  return false;
};

export const logout = () => {
  currentUser = null;
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
  window.location.href = '/#/login';
};

export const subscribeToSession = (callback: () => void) => {
  window.addEventListener(SESSION_CHANGE_EVENT, callback);
  window.addEventListener('storage', callback);
  return () => {
    window.removeEventListener(SESSION_CHANGE_EVENT, callback);
    window.removeEventListener('storage', callback);
  };
};

export const getGrievances = async (): Promise<Grievance[]> => {
  return await db.grievances.find() || [];
};

export const saveGrievance = async (grievance: Grievance) => {
  return await db.grievances.insertOne(grievance);
};

export const updateGrievance = async (grievance: Grievance) => {
  const { id, ...update } = grievance;
  return await db.grievances.updateOne({ id }, update);
};

export const sendMessage = async (grievanceId: string, content: string) => {
  const user = getCurrentUser();
  if (!user) return;

  const grievances = await getGrievances();
  const g = grievances.find(x => x.id === grievanceId);
  if (!g) return;

  const newMessage: Message = {
    id: 'MSG-' + Math.random().toString(36).substr(2, 9),
    senderId: user.id,
    senderRole: user.role,
    content,
    timestamp: Date.now()
  };

  const updated = {
    ...g,
    conversation: [...(g.conversation || []), newMessage],
    notificationsSent: [
      ...(g.notificationsSent || []),
      { type: 'EMAIL', timestamp: Date.now(), message: `Simulated Email: New message from ${user.role}` }
    ]
  };

  await updateGrievance(updated);
  return updated;
};

export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  return staff.length > 0 ? staff[0].id : 'ADM-PRIN';
};

export const getUserById = async (id: string): Promise<User | null> => {
  return await db.users.findOne({ id });
};

import React, { useState, useRef, useEffect } from 'react';
import { analyzeGrievanceState } from '../services/geminiService';
import { ChatMessage, Grievance, Status, Department, Severity } from '../types';
import { saveGrievance, getResponsibleStaffId, getCurrentUser } from '../store';

type ChatState = 'IDLE' | 'COLLECTING' | 'REVIEW' | 'DONE';

const GrievanceChatbot: React.FC = () => {
  const currentUser = getCurrentUser();
  const [state, setState] = useState<ChatState>('IDLE');
  const [isAnonymous, setIsAnonymous] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: `Identity verified. Greetings, ${currentUser?.name}. I am the AI Redressal Assistant. Briefly state the institutional concern you wish to report.` }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [analysis, setAnalysis] = useState<any>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => scrollRef.current?.scrollIntoView({ behavior: 'smooth' }), [messages, isTyping]);

  const addBotMessage = (content: string) => {
    setMessages(prev => [...prev, { role: 'assistant', content }]);
  };

  const handleSubmission = async (userMessage: string) => {
    setIsTyping(true);
    try {
      if (state === 'IDLE' || state === 'COLLECTING') {
        const result = await analyzeGrievanceState(userMessage, messages);
        setAnalysis(result);

        if (!result.isDetailedEnough) {
          setState('COLLECTING');
          addBotMessage(result.followUpQuestion || "Institutional protocols require more specific details. Please clarify the location and nature of the concern.");
        } else {
          setState('REVIEW');
          addBotMessage(
            `Data extraction complete. I've detected a **${result.sentiment}** tone.\n\n` +
            `**Summary:** ${result.summary}\n` +
            `**Dept:** ${result.department}\n` +
            `**Impact:** ${result.severity.toUpperCase()}\n\n` +
            `Type **'Confirm'** to finalize filing.`
          );
        }
      } else if (state === 'REVIEW') {
        if (/confirm|yes|correct|ok|submit/i.test(userMessage)) {
          await finalizeGrievance();
        } else {
          addBotMessage("Re-analyzing session context...");
          const updatedResult = await analyzeGrievanceState(userMessage, messages);
          setAnalysis(updatedResult);
          addBotMessage(`Revised Summary: ${updatedResult.summary}\n\nProceed?`);
        }
      }
    } catch (e) {
      addBotMessage("Infrastructure error: AI gateway timeout.");
    } finally {
      setIsTyping(false);
    }
  };

  const finalizeGrievance = async () => {
    const grievanceId = 'KIT-' + Math.floor(1000 + Math.random() * 9000);
    const now = Date.now();
    const dept = (analysis?.department as Department) || Department.OTHER;
    const staffId = await getResponsibleStaffId(dept);

    const newGrievance: Grievance = {
      id: grievanceId,
      title: analysis?.summary || "General Concern",
      timestamp: now,
      description: messages.filter(m => m.role === 'user').map(m => m.content).join('\n'),
      department: dept,
      severity: (analysis?.severity as Severity) || Severity.LOW,
      status: Status.PENDING,
      isAnonymous: isAnonymous,
      studentId: currentUser?.id || 'ANON',
      assignedToId: staffId, 
      lastStatusChange: now,
      history: [{ status: Status.PENDING, timestamp: now, userId: 'SYSTEM', remark: 'Case registered with AI sentiment analysis.' }],
      remarks: [],
      notificationsSent: [{ type: 'EMAIL', timestamp: now, message: 'Filing Confirmation Sent' }],
      conversation: [],
      sentiment: analysis?.sentiment,
      summary: analysis?.summary
    };

    await saveGrievance(newGrievance);
    addBotMessage(`✅ **Verified.** Ref: **#${grievanceId}**.\n\nRouted to **${dept}**. ${isAnonymous ? "Filing is Anonymous." : "Filing linked to profile."}`);
    setState('DONE');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;
    const msg = input.trim();
    setMessages(prev => [...prev, { role: 'user', content: msg }]);
    setInput('');
    handleSubmission(msg);
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-14rem)] bg-white rounded-3xl border border-slate-200 shadow-xl flex flex-col overflow-hidden">
      <div className="bg-slate-900 p-6 text-white flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center font-black">AI</div>
          <div>
            <h3 className="font-bold">KIT UGRS Assistant</h3>
            <p className="text-[10px] opacity-60 font-bold uppercase tracking-widest">Sentiment-Aware Engine</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <label className="flex items-center gap-2 cursor-pointer">
            <span className="text-[10px] font-bold uppercase opacity-60">Anonymous Mode</span>
            <input 
              type="checkbox" 
              checked={isAnonymous} 
              onChange={() => setIsAnonymous(!isAnonymous)}
              className="w-4 h-4 accent-indigo-500"
            />
          </label>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/30">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] px-5 py-3 rounded-2xl text-sm font-medium shadow-sm border ${
              msg.role === 'user' ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-white text-slate-700 border-slate-200'
            }`}>
              {msg.content}
            </div>
          </div>
        ))}
        {isTyping && <div className="text-[10px] font-bold text-slate-400 animate-pulse">AI IS ANALYZING...</div>}
        <div ref={scrollRef}></div>
      </div>

      <div className="p-6 bg-white border-t">
        <form onSubmit={handleSubmit} className="flex gap-3">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={state === 'DONE' ? "Session concluded." : "Describe your grievance..."}
            disabled={state === 'DONE' || isTyping}
            className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-semibold focus:ring-2 focus:ring-indigo-500 outline-none"
          />
          <button type="submit" disabled={!input.trim() || isTyping || state === 'DONE'} className="bg-slate-950 text-white px-10 py-4 rounded-2xl font-bold text-xs uppercase hover:bg-slate-800 transition-all">Send</button>
        </form>
      </div>
    </div>
  );
};

export default GrievanceChatbot;

import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getGrievances, updateGrievance, getCurrentUser, sendMessage, getUserById } from '../store';
import { Grievance, Status, UserRole, Department, User } from '../types';
import { COLORS } from '../constants';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [student, setStudent] = useState<User | null>(null);
  const [chatInput, setChatInput] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const refreshGrievance = async () => {
    const id = location.state?.grievanceId;
    if (id) {
      const all = await getGrievances();
      const g = all.find(x => x.id === id);
      if (g) {
        setGrievance(g);
        if (!g.isAnonymous) {
          const u = await getUserById(g.studentId);
          setStudent(u);
        }
      }
    }
  };

  useEffect(() => {
    refreshGrievance();
    const interval = setInterval(refreshGrievance, 5000);
    return () => clearInterval(interval);
  }, [location.state]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [grievance?.conversation]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || !grievance) return;
    const res = await sendMessage(grievance.id, chatInput);
    if (res) {
      setGrievance(res);
      setChatInput('');
    }
  };

  const handleUpdateStatus = async (status: Status) => {
    if (!grievance || !currentUser) return;
    const now = Date.now();
    const updated = {
      ...grievance,
      status,
      lastStatusChange: now,
      history: [...grievance.history, { status, timestamp: now, userId: currentUser.id, remark: `Status updated to ${status}` }]
    };
    await updateGrievance(updated);
    setGrievance(updated);
  };

  const askAi = async () => {
    if (!grievance) return;
    setIsAiLoading(true);
    try {
      const res = await getStaffAssistance(grievance.description, grievance.sentiment || 'Neutral');
      setAiResponse(res || 'Analysis failed.');
    } catch (e) {
      setAiResponse('AI Gateway error.');
    } finally {
      setIsAiLoading(false);
    }
  };

  if (!grievance || !currentUser) return <div className="p-20 text-center text-slate-400 font-bold">Select a case from the dashboard.</div>;

  return (
    <div className="h-[calc(100vh-12rem)] flex gap-6 animate-in fade-in duration-500">
      {/* Sidebar: Case Info */}
      <div className="w-[340px] flex flex-col gap-4">
        <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm">
          <div className="flex justify-between items-start mb-6">
            <h3 className="font-black text-slate-900 text-lg">#{grievance.id}</h3>
            <span className={`${COLORS.status[grievance.status]} scale-90`}>{grievance.status}</span>
          </div>

          <div className="space-y-4">
            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Sentiment</p>
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${grievance.sentiment === 'Angry' || grievance.sentiment === 'Urgent' ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
                <span className="text-xs font-bold text-slate-700">{grievance.sentiment || 'Detected'}</span>
              </div>
            </div>

            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Department</p>
              <span className="text-xs font-bold text-slate-700">{grievance.department}</span>
            </div>
          </div>

          <div className="mt-8 space-y-2">
            <button onClick={() => handleUpdateStatus(Status.IN_PROGRESS)} className="w-full py-2 bg-indigo-50 text-indigo-700 font-bold text-xs rounded-lg hover:bg-indigo-100 transition-all">Start Handling</button>
            <button onClick={() => handleUpdateStatus(Status.RESOLVED)} className="w-full py-2 bg-emerald-600 text-white font-bold text-xs rounded-lg hover:bg-emerald-700 transition-all shadow-md">Mark Resolved</button>
          </div>
        </div>

        {/* User Profile Card */}
        <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Student Identity</h4>
          {grievance.isAnonymous ? (
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center text-slate-300">
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg>
              </div>
              <div>
                <p className="text-sm font-bold text-slate-900">Protected Identity</p>
                <p className="text-[10px] font-bold text-indigo-600 uppercase">Anonymous Mode Active</p>
              </div>
            </div>
          ) : student ? (
            <div className="space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-600 text-white rounded-full flex items-center justify-center font-black text-lg">
                  {student.name[0]}
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-900">{student.name}</p>
                  <p className="text-[10px] font-bold text-slate-400">{student.id}</p>
                </div>
              </div>
              <p className="text-xs font-medium text-slate-500 break-all">{student.email}</p>
            </div>
          ) : <p className="text-xs italic text-slate-400">Loading profile...</p>}
        </div>

        {/* AI Assistant Card */}
        <div className="flex-1 bg-slate-900 rounded-3xl p-6 text-white shadow-xl flex flex-col">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 bg-indigo-500 rounded-lg flex items-center justify-center font-black text-[10px]">AI</div>
            <p className="text-xs font-bold uppercase tracking-widest">Mediator Suggestion</p>
          </div>
          <div className="flex-1 overflow-y-auto mb-4 scrollbar-hide">
            {isAiLoading ? <p className="text-xs animate-pulse">Consulting Gemini...</p> : (
              <p className="text-[11px] leading-relaxed text-slate-300 italic">"{aiResponse || 'No active suggestions.'}"</p>
            )}
          </div>
          <button onClick={askAi} className="w-full py-2 bg-indigo-500/20 text-indigo-300 border border-indigo-500/30 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500/40 transition-all">Get Support</button>
        </div>
      </div>

      {/* Main Chat: Messenger View */}
      <div className="flex-1 flex flex-col bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Active Conversation</p>
          </div>
          <div className="flex gap-2">
            {grievance.notificationsSent.filter(n => n.type === 'EMAIL').length > 0 && (
              <span className="text-[9px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded-full border border-emerald-100 uppercase">📧 Email Notified</span>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/20">
          <div className="flex justify-start">
             <div className="max-w-[80%] bg-indigo-50 border border-indigo-100 p-5 rounded-2xl">
                <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-2">Original Grievance</p>
                <p className="text-sm font-medium text-slate-800 italic leading-relaxed">"{grievance.description}"</p>
             </div>
          </div>

          {(grievance.conversation || []).map((msg) => (
            <div key={msg.id} className={`flex ${msg.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[70%] px-5 py-3 rounded-2xl text-sm font-medium shadow-sm border ${
                msg.senderId === currentUser.id 
                  ? 'bg-slate-900 text-white border-slate-800 rounded-br-none' 
                  : 'bg-white text-slate-700 border-slate-200 rounded-bl-none'
              }`}>
                {msg.content}
                <div className={`text-[9px] mt-1 opacity-50 ${msg.senderId === currentUser.id ? 'text-right' : 'text-left'}`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        <div className="p-6 border-t">
          <form onSubmit={handleSendMessage} className="flex gap-3">
            <input 
              type="text" 
              value={chatInput}
              onChange={e => setChatInput(e.target.value)}
              placeholder="Type your message to the student..."
              className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-semibold focus:ring-2 focus:ring-slate-950 outline-none"
            />
            <button type="submit" disabled={!chatInput.trim()} className="bg-slate-950 text-white px-8 py-4 rounded-2xl font-bold text-xs uppercase hover:bg-slate-800 transition-all">Send</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ManagementConsole;

import React, { useMemo, useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { getGrievances, getCurrentUser, subscribeToSession } from '../store';
import { UserRole, Status, Grievance } from '../types';
import { COLORS } from '../constants';

const Dashboard: React.FC = () => {
  const [user, setUser] = useState(getCurrentUser());
  const [grievances, setGrievances] = useState<Grievance[]>([]);
  const navigate = useNavigate();

  const refresh = async () => {
    const data = await getGrievances();
    setGrievances(data);
  };

  useEffect(() => {
    refresh();
    const cleanup = subscribeToSession(() => {
      setUser(getCurrentUser());
      refresh();
    });
    return cleanup;
  }, []);

  if (!user) return null;

  if (user.role === UserRole.STUDENT) {
    const mine = grievances.filter(g => g.studentId === user.id);
    const stats = {
      total: mine.length,
      pending: mine.filter(g => g.status === Status.PENDING).length,
      progress: mine.filter(g => g.status === Status.IN_PROGRESS).length,
      resolved: mine.filter(g => g.status === Status.RESOLVED).length,
    };

    return (
      <div className="space-y-8 animate-in fade-in duration-700">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <StatCard label="Total Filed" value={stats.total} subtext="Institutional record" icon="📄" />
          <StatCard label="Pending" value={stats.pending} subtext="Awaiting review" icon="🕒" color="text-amber-500" />
          <StatCard label="In Progress" value={stats.progress} subtext="Staff handling" icon="📈" color="text-indigo-600" />
          <StatCard label="Resolved" value={stats.resolved} subtext="Verified closed" icon="✅" color="text-emerald-600" />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <ActionCard 
            title="Lodge New Concern" 
            desc="Use our AI-assisted filing system to submit institutional grievances with sentiment tracking."
            btnText="Launch AI Assistant"
            onClick={() => navigate('/chatbot')}
          />
          <ActionCard 
            title="Case History" 
            desc="Track the communication history and resolution progress of your existing reports."
            btnText="Open Tracker"
            variant="outline"
            onClick={() => navigate('/track')}
          />
        </div>

        <div className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
            <h3 className="font-black text-slate-900 tracking-tight">Recent Activity</h3>
            <Link to="/track" className="text-xs font-black text-indigo-600 uppercase tracking-widest hover:underline">Full Audit &rarr;</Link>
          </div>
          <div className="divide-y divide-slate-100">
            {mine.slice(0, 3).map(g => (
              <div key={g.id} className="px-8 py-6 hover:bg-slate-50 transition-all cursor-pointer" onClick={() => navigate('/manage', { state: { grievanceId: g.id } })}>
                <div className="flex justify-between items-start mb-3">
                  <h4 className="font-bold text-slate-800">{g.title || 'General Grievance'}</h4>
                  <span className={COLORS.status[g.status]}>{g.status}</span>
                </div>
                <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest text-slate-400">
                   <span className="bg-slate-100 px-2 py-0.5 rounded text-slate-600">{g.id}</span>
                   <span>•</span>
                   <span className="text-indigo-600">{g.department}</span>
                   <span>•</span>
                   <span className="flex items-center gap-1">
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
                      {(g.conversation || []).length} Messages
                   </span>
                </div>
              </div>
            ))}
            {mine.length === 0 && (
              <div className="p-20 text-center text-slate-400 text-sm font-medium italic">No active cases found.</div>
            )}
          </div>
        </div>
      </div>
    );
  }

  const worklist = grievances.filter(g => g.assignedToId === user.id || user.role === UserRole.ADMIN);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="flex justify-between items-end">
         <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tighter">Case Manager</h2>
            <p className="text-slate-500 font-medium">Resolving institutional concerns with AI-driven empathy.</p>
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard label="Assigned" value={worklist.length} subtext="Active cases" icon="📂" />
        <StatCard label="Unread" value={worklist.filter(g => g.conversation && g.conversation.length > 0 && g.conversation[g.conversation.length - 1].senderRole === UserRole.STUDENT).length} subtext="Student messages" icon="💬" color="text-indigo-600" />
        <StatCard label="Urgent" value={worklist.filter(g => g.sentiment === 'Angry' || g.sentiment === 'Urgent').length} subtext="Critical sentiment" icon="🔥" color="text-red-600" />
        <StatCard label="Resolved" value={worklist.filter(g => g.status === Status.RESOLVED).length} subtext="Case success" icon="✅" color="text-emerald-600" />
      </div>

      <div className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-10 py-8 border-b border-slate-100">
          <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">Active Worklist</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-100">
              <tr>
                <th className="px-10 py-5">Case ID</th>
                <th className="px-10 py-5">Summary</th>
                <th className="px-10 py-5">Sentiment</th>
                <th className="px-10 py-5">Identity</th>
                <th className="px-10 py-5">Status</th>
                <th className="px-10 py-5 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {worklist.map(g => (
                <tr key={g.id} className="hover:bg-indigo-50/30 transition-all cursor-pointer group" onClick={() => navigate('/manage', { state: { grievanceId: g.id } })}>
                  <td className="px-10 py-6 font-black text-slate-900 text-sm">#{g.id}</td>
                  <td className="px-10 py-6">
                    <p className="text-sm font-bold text-slate-800 line-clamp-1">{g.title || g.description}</p>
                    <p className="text-[10px] font-medium text-slate-400 mt-0.5">{g.department}</p>
                  </td>
                  <td className="px-10 py-6">
                    <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      g.sentiment === 'Angry' || g.sentiment === 'Urgent' ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-slate-100 text-slate-500'
                    }`}>
                      {g.sentiment || 'Neutral'}
                    </span>
                  </td>
                  <td className="px-10 py-6">
                    {g.isAnonymous ? (
                      <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Anonymous</span>
                    ) : (
                      <span className="text-[10px] font-black text-slate-700 uppercase tracking-widest">STU-{g.studentId.split('-').pop()}</span>
                    )}
                  </td>
                  <td className="px-10 py-6">
                    <span className={`${COLORS.status[g.status]} scale-90`}>{g.status}</span>
                  </td>
                  <td className="px-10 py-6 text-right">
                    <button className="bg-slate-900 text-white text-[9px] font-black px-4 py-2 rounded-xl opacity-0 group-hover:opacity-100 transition-all uppercase tracking-widest">Open Chat</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ label, value, subtext, icon, color = 'text-slate-900' }) => (
  <div className="bg-white p-8 rounded-[32px] border border-slate-200 shadow-sm space-y-4">
    <div className="flex justify-between items-start">
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{label} {icon}</p>
    </div>
    <div>
      <p className={`text-4xl font-black tracking-tighter ${color}`}>{value}</p>
      <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase tracking-widest">{subtext}</p>
    </div>
  </div>
);

const ActionCard = ({ title, desc, btnText, onClick, variant = 'primary' }) => (
  <div className="bg-white p-10 rounded-[40px] border border-slate-200 shadow-sm space-y-8">
    <div className="space-y-3">
      <h3 className="text-2xl font-black text-slate-900 tracking-tight">{title}</h3>
      <p className="text-sm text-slate-500 font-medium leading-relaxed">{desc}</p>
    </div>
    <button 
      onClick={onClick}
      className={`w-full py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
        variant === 'primary' 
        ? 'bg-slate-900 text-white hover:bg-slate-800 shadow-xl shadow-slate-200' 
        : 'bg-slate-50 border border-slate-200 text-slate-900 hover:bg-white'
      }`}
    >
      {btnText}
    </button>
  </div>
);

export default Dashboard;

import { Grievance, User, UserRole, Department, Status, Message } from './types';
import { db } from './db';

let currentUser: User | null = null;
const SESSION_CHANGE_EVENT = 'kit_session_change';

export const setSession = (user: User, token: string) => {
  currentUser = user;
  localStorage.setItem('access_token', token);
  localStorage.setItem('user_profile', JSON.stringify(user));
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
};

export const getCurrentUser = (): User | null => {
  if (currentUser) return currentUser;
  const saved = localStorage.getItem('user_profile');
  if (saved) {
    try {
      currentUser = JSON.parse(saved);
      return currentUser;
    } catch (e) {
      return null;
    }
  }
  return null;
};

// Fix: Add missing isAuthenticated check used in ProtectedRoute (App.tsx)
export const isAuthenticated = (): boolean => {
  return !!localStorage.getItem('access_token');
};

export const login = async (userIdOrEmail: string, password: string): Promise<boolean> => {
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  currentUser = null;

  let user = await db.users.findOne({ id: userIdOrEmail, password });
  if (!user) user = await db.users.findOne({ email: userIdOrEmail, password });

  if (user) {
    const { password: _, ...profile } = user;
    setSession(profile as User, 'kit-session-' + Date.now());
    return true;
  }
  return false;
};

export const logout = () => {
  currentUser = null;
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
  window.location.href = '/#/login';
};

export const subscribeToSession = (callback: () => void) => {
  window.addEventListener(SESSION_CHANGE_EVENT, callback);
  window.addEventListener('storage', callback);
  return () => {
    window.removeEventListener(SESSION_CHANGE_EVENT, callback);
    window.removeEventListener('storage', callback);
  };
};

export const getGrievances = async (): Promise<Grievance[]> => {
  return await db.grievances.find() || [];
};

export const saveGrievance = async (grievance: Grievance) => {
  return await db.grievances.insertOne(grievance);
};

export const updateGrievance = async (grievance: Grievance) => {
  const { id, ...update } = grievance;
  return await db.grievances.updateOne({ id }, update);
};

export const sendMessage = async (grievanceId: string, content: string) => {
  const user = getCurrentUser();
  if (!user) return;

  const grievances = await getGrievances();
  const g = grievances.find(x => x.id === grievanceId);
  if (!g) return;

  const newMessage: Message = {
    id: 'MSG-' + Math.random().toString(36).substr(2, 9),
    senderId: user.id,
    senderRole: user.role,
    content,
    timestamp: Date.now()
  };

  const updated = {
    ...g,
    conversation: [...(g.conversation || []), newMessage],
    notificationsSent: [
      ...(g.notificationsSent || []),
      { type: 'EMAIL', timestamp: Date.now(), message: `Simulated Email: New message from ${user.role}` }
    ]
  };

  await updateGrievance(updated);
  return updated;
};

export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  return staff.length > 0 ? staff[0].id : 'ADM-PRIN';
};

export const getUserById = async (id: string): Promise<User | null> => {
  return await db.users.findOne({ id });
};

export enum Department {
  TECHNICAL = 'Technical',
  INFRASTRUCTURE = 'Infrastructure',
  ACADEMIC = 'Academic',
  ADMINISTRATIVE = 'Administrative',
  MESS = 'Mess',
  HOSTEL = 'Hostel',
  TRANSPORT = 'Transport',
  OTHER = 'Other'
}

export enum Severity {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high',
  CRITICAL = 'critical'
}

export enum Status {
  PENDING = 'pending',
  IN_PROGRESS = 'in-progress',
  RESOLVED = 'resolved',
  CLOSED = 'closed'
}

export enum UserRole {
  STUDENT = 'Student',
  STAFF = 'Staff',
  ADMIN = 'Admin'
}

export interface Attachment {
  name: string;
  type: string;
  data: string; // base64
}

export interface Message {
  id: string;
  senderId: string;
  senderRole: UserRole;
  senderName?: string; // Added for clearer chat
  content: string;
  timestamp: number;
}

export interface GrievanceHistory {
  status: Status;
  timestamp: number;
  userId: string;
  remark?: string;
  reassignedFrom?: Department;
  reassignedTo?: Department;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  department?: Department;
  email: string;
}

export interface Grievance {
  id: string;
  title: string;
  timestamp: number;
  description: string;
  department: Department;
  severity: Severity;
  status: Status;
  isAnonymous: boolean;
  studentId: string;
  assignedToId: string;
  lastStatusChange: number;
  history: GrievanceHistory[];
  remarks: string[];
  attachments?: Attachment[];
  notificationsSent: { type: string; timestamp: number; message: string }[];
  // AI Enhanced fields
  sentiment?: 'Positive' | 'Neutral' | 'Frustrated' | 'Angry' | 'Urgent';
  summary?: string;
  conversation: Message[];
  fingerprint?: string; 
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
  attachments?: Attachment[];
}

