export const transferGrievance = async (grievanceId: string, toDept: Department, toStaffId: string, reason: string) => {
  const user = getCurrentUser();
  if (!user) return;

  const grievances = await getGrievances();
  const g = grievances.find(x => x.id === grievanceId);
  if (!g) return;

  const now = Date.now();
  const updated: Grievance = {
    ...g,
    department: toDept,
    assignedToId: toStaffId,
    lastStatusChange: now,
    history: [
      ...(g.history || []),
      { 
        status: g.status, 
        timestamp: now, 
        userId: user.id, 
        remark: `Transferred to ${toDept}. Reason: ${reason}`,
        reassignedFrom: g.department,
        reassignedTo: toDept
      }
    ]
  };

  await updateGrievance(updated);
  return updated;
};

