import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getGrievances, updateGrievance, getCurrentUser, sendMessage, getUserById, getAllStaff, transferGrievance } from '../store';
import { Grievance, Status, UserRole, Department, User } from '../types';
import { COLORS } from '../constants';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [student, setStudent] = useState<User | null>(null);
  const [staffList, setStaffList] = useState<User[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Transfer state
  const [showTransfer, setShowTransfer] = useState(false);
  const [transferDept, setTransferDept] = useState<Department | ''>('');
  const [transferStaffId, setTransferStaffId] = useState('');
  const [transferReason, setTransferReason] = useState('');

  const chatEndRef = useRef<HTMLDivElement>(null);

  const refreshGrievance = async () => {
    const id = location.state?.grievanceId;
    if (id) {
      const all = await getGrievances();
      const g = all.find(x => x.id === id);
      if (g) {
        setGrievance(g);
        if (!g.isAnonymous) {
          const u = await getUserById(g.studentId);
          setStudent(u);
        }
      }
    }
  };

  useEffect(() => {
    refreshGrievance();
    getAllStaff().then(setStaffList);
    const interval = setInterval(refreshGrievance, 5000);
    return () => clearInterval(interval);
  }, [location.state]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [grievance?.conversation]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || !grievance) return;
    const res = await sendMessage(grievance.id, chatInput);
    if (res) {
      setGrievance(res);
      setChatInput('');
    }
  };

  const handleUpdateStatus = async (status: Status) => {
    if (!grievance || !currentUser) return;
    const now = Date.now();
    const updated = {
      ...grievance,
      status,
      lastStatusChange: now,
      history: [...grievance.history, { status, timestamp: now, userId: currentUser.id, remark: `Status updated to ${status}` }]
    };
    await updateGrievance(updated);
    setGrievance(updated);
  };

  const handleTransfer = async () => {
    if (!grievance || !transferDept || !transferStaffId || !transferReason) return;
    const res = await transferGrievance(grievance.id, transferDept as Department, transferStaffId, transferReason);
    if (res) {
      setGrievance(res);
      setShowTransfer(false);
      // Navigate away as it's no longer assigned to this staff if they transferred it out
      if (currentUser?.role === UserRole.STAFF && res.assignedToId !== currentUser.id) {
        navigate('/dashboard');
      }
    }
  };

  const askAi = async () => {
    if (!grievance) return;
    setIsAiLoading(true);
    try {
      const res = await getStaffAssistance(grievance.description, grievance.sentiment || 'Neutral');
      setAiResponse(res || 'Analysis failed.');
    } catch (e) {
      setAiResponse('AI Gateway error.');
    } finally {
      setIsAiLoading(false);
    }
  };

  if (!grievance || !currentUser) return <div className="p-20 text-center text-slate-400 font-bold">Select a case from the dashboard.</div>;

  return (
    <div className="flex flex-col lg:flex-row gap-6 h-[calc(100vh-160px)] animate-in fade-in duration-500 overflow-hidden">
      {/* Sidebar: Case Info & Identity */}
      <div className="lg:w-[360px] flex flex-col gap-4 overflow-y-auto custom-scrollbar pr-1">

        {/* Case Core Card */}
        <div className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-900 text-lg tracking-tight">#{grievance.id}</h3>
            <span className={`${COLORS.status[grievance.status]} px-2 py-1 rounded text-[10px] font-bold uppercase`}>{grievance.status}</span>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center p-3 bg-slate-50 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sentiment</span>
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${grievance.sentiment === 'Angry' || grievance.sentiment === 'Urgent' ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
                <span className="text-xs font-bold text-slate-700">{grievance.sentiment || 'Detected'}</span>
              </div>
            </div>

