import { Grievance, User, UserRole, Department, Status, Message } from './types';
import { db } from './db';

let currentUser: User | null = null;
const SESSION_CHANGE_EVENT = 'kit_session_change';

export const setSession = (user: User, token: string) => {
  currentUser = user;
  localStorage.setItem('access_token', token);
  localStorage.setItem('user_profile', JSON.stringify(user));
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
};

export const getCurrentUser = (): User | null => {
  if (currentUser) return currentUser;
  const saved = localStorage.getItem('user_profile');
  if (saved) {
    try {
      currentUser = JSON.parse(saved);
      return currentUser;
    } catch (e) {
      return null;
    }
  }
  return null;
};

export const isAuthenticated = (): boolean => {
  return !!localStorage.getItem('access_token');
};

export const login = async (userIdOrEmail: string, password: string): Promise<boolean> => {
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  currentUser = null;

  let user = await db.users.findOne({ id: userIdOrEmail, password });
  if (!user) user = await db.users.findOne({ email: userIdOrEmail, password });

  if (user) {
    const { password: _, ...profile } = user;
    setSession(profile as User, 'kit-session-' + Date.now());
    return true;
  }
  return false;
};

export const logout = () => {
  currentUser = null;
  localStorage.removeItem('access_token');
  localStorage.removeItem('user_profile');
  window.dispatchEvent(new Event(SESSION_CHANGE_EVENT));
  window.location.href = '/#/login';
};

export const subscribeToSession = (callback: () => void) => {
  window.addEventListener(SESSION_CHANGE_EVENT, callback);
  window.addEventListener('storage', callback);
  return () => {
    window.removeEventListener(SESSION_CHANGE_EVENT, callback);
    window.removeEventListener('storage', callback);
  };
};

export const getGrievances = async (): Promise<Grievance[]> => {
  return await db.grievances.find() || [];
};

export const saveGrievance = async (grievance: Grievance) => {
  return await db.grievances.insertOne(grievance);
};

export const updateGrievance = async (grievance: Grievance) => {
  const { id, ...update } = grievance;
  return await db.grievances.updateOne({ id }, update);
};

export const sendMessage = async (grievanceId: string, content: string) => {
  const user = getCurrentUser();
  if (!user) return;

  const grievances = await getGrievances();
  const g = grievances.find(x => x.id === grievanceId);
  if (!g) return;

  const newMessage: Message = {
    id: 'MSG-' + Math.random().toString(36).substr(2, 9),
    senderId: user.id,
    senderRole: user.role,
    senderName: user.name,
    content,
    timestamp: Date.now()
  };

  const updated = {
    ...g,
    conversation: [...(g.conversation || []), newMessage],
    notificationsSent: [
      ...(g.notificationsSent || []),
      { type: 'EMAIL', timestamp: Date.now(), message: `Notification: New message from ${user.role} regarding #${g.id}` }
    ]
  };

  await updateGrievance(updated);
  return updated;
};

export const transferGrievance = async (grievanceId: string, toDept: Department, toStaffId: string, reason: string) => {
  const user = getCurrentUser();
  if (!user) return;

  const grievances = await getGrievances();
  const g = grievances.find(x => x.id === grievanceId);
  if (!g) return;

  const now = Date.now();
  const updated: Grievance = {
    ...g,
    department: toDept,
    assignedToId: toStaffId,
    lastStatusChange: now,
    history: [
      ...(g.history || []),
      { 
        status: g.status, 
        timestamp: now, 
        userId: user.id, 
        remark: `Transferred from ${g.department} to ${toDept}. Reason: ${reason}`,
        reassignedFrom: g.department,
        reassignedTo: toDept
      }
    ]
  };

  await updateGrievance(updated);
  return updated;
};

export const getAllStaff = async (): Promise<User[]> => {
  return await db.users.find({ role: UserRole.STAFF }) || [];
};

export const getResponsibleStaffId = async (department: Department): Promise<string> => {
  const staff = await db.users.find({ role: UserRole.STAFF, department });
  return staff.length > 0 ? staff[0].id : 'ADM-PRIN';
};

export const getUserById = async (id: string): Promise<User | null> => {
  return await db.users.findOne({ id });
}

