import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeGrievanceState = async (complaintText: string, history: ChatMessage[]) => {
  const historyText = history.map(m => `${m.role}: ${m.content}`).join("\n");

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `HISTORY:
    ${historyText}

    NEW USER INPUT:
    "${complaintText}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          isDetailedEnough: { type: Type.BOOLEAN },
          followUpQuestion: { type: Type.STRING },
          summary: { type: Type.STRING },
          department: { type: Type.STRING },
          severity: { type: Type.STRING },
          sentiment: { 
            type: Type.STRING, 
            description: "Choose: Positive, Neutral, Frustrated, Angry, Urgent" 
          },
          initialStatus: { 
            type: Type.STRING, 
            description: "Suggested status: pending, in-progress, or resolved. Default to 'pending'." 
          },
          fingerprint: { type: Type.STRING }
        },
        required: ["isDetailedEnough", "summary", "department", "severity", "sentiment", "initialStatus", "fingerprint"],
      },
      systemInstruction: `You are the KIT Redressal Analyst. 
      Analyze the complaint for sentiment.
      Map departments to: Technical, Infrastructure, Academic, Administrative, Mess, Hostel, Transport.
      Determine if the grievance is new (status: pending) or if the user is reporting a resolution (status: resolved).`,
    },
  });

  return JSON.parse(response.text || '{}');
};

export const getStaffAssistance = async (description: string, sentiment: string) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Complaint: "${description}"
    Detected Sentiment: ${sentiment}`,
    config: {
      systemInstruction: `You are a professional Staff Mediator. 
      The student seems ${sentiment}. Suggest a resolution strategy that addresses this emotion and the technical issue.`,
    },
  });
  return response.text;
};

