          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sentiment</span>
              <div className="flex items-center gap-2">
                <div className={`w-2.5 h-2.5 rounded-full ${grievance.sentiment === 'Angry' || grievance.sentiment === 'Urgent' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]'}`}></div>
                <span className="text-xs font-bold text-slate-700">{grievance.sentiment || 'Evaluating'}</span>
              </div>
            </div>

            <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Routing</span>
              <span className="text-xs font-bold text-slate-700">{grievance.department}</span>
            </div>
          </div>

          <div className="mt-8 flex flex-col gap-3">
            <div className="grid grid-cols-2 gap-3">
               <button onClick={() => handleUpdateStatus(Status.IN_PROGRESS)} className="py-3 bg-indigo-50 text-indigo-700 font-bold text-[11px] rounded-xl uppercase hover:bg-indigo-100 transition-all active:scale-95">Start Handling</button>
               <button onClick={() => handleUpdateStatus(Status.RESOLVED)} className="py-3 bg-emerald-600 text-white font-bold text-[11px] rounded-xl uppercase hover:bg-emerald-700 transition-all shadow-lg active:scale-95">Mark Resolved</button>
            </div>
            <button onClick={() => setShowTransfer(true)} className="w-full py-3 bg-slate-100 text-slate-600 font-bold text-[11px] rounded-xl uppercase hover:bg-slate-200 transition-all active:scale-95">Transfer Case</button>
