                <p className="text-[11px] font-black uppercase tracking-[0.2em]">Mediator Advice</p>
             </div>
             {isAiLoading && <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>}
          </div>

          <div className="min-h-[80px]">
            <p className="text-[12px] leading-relaxed text-indigo-200/90 font-medium italic">
              {aiResponse || 'Consult the institutional AI to generate a resolution strategy or empathetic response based on the detected sentiment.'}
            </p>
          </div>

          <button 
            onClick={async () => {
                if (!grievance) return;
                setIsAiLoading(true);
                try {
                  const res = await getStaffAssistance(grievance.description, grievance.sentiment || 'Neutral');
                  setAiResponse(res || 'Unable to generate analysis at this time.');
                } catch (e) {
                  setAiResponse('Institutional AI Gateway error. Please try again.');
                } finally {
                  setIsAiLoading(false);
                }
            }} 
            disabled={isAiLoading}
            className="w-full py-3.5 bg-white text-indigo-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 active:scale-95 transition-all disabled:opacity-50 shadow-lg shadow-indigo-950/20"
          >
            Ask for Guidance
          </button>
        </div>
      </div>

      {/* RIGHT COLUMN: Communication Hub */}
      <div className="flex-1 flex flex-col bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden min-h-0">
        {/* Chat Header */}
        <div className="px-8 py-5 border-b flex items-center justify-between bg-white/80 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-4">
             <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.6)]"></div>
             <div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Communication Channel</p>
               <p className="text-xs font-bold text-slate-700 mt-0.5">Active mediation with student</p>
             </div>
          </div>
          <div className="flex items-center gap-3">
            {grievance.notificationsSent.some(n => n.type === 'EMAIL') && (
              <span className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full border border-indigo-100 uppercase tracking-tighter">📧 Notification Dispatched</span>
            )}
          </div>
        </div>

        {/* Conversation Feed */}
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/10 custom-scrollbar">
          {/* Grievance Statement */}
          <div className="flex justify-center mb-10">
             <div className="max-w-[85%] bg-white border border-slate-100 p-8 rounded-[32px] shadow-sm relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-500 group-hover:w-2 transition-all"></div>
                <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-3">Institutional Complaint Statement</p>
                <p className="text-[15px] font-semibold text-slate-800 leading-relaxed italic">"{grievance.description}"</p>
                <div className="mt-4 flex items-center gap-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                  <span>Logged {new Date(grievance.timestamp).toLocaleDateString()}</span>
                  <span>•</span>
                  <span>Impact: {grievance.severity}</span>
                </div>
             </div>
          </div>

          {(grievance.conversation || []).map((msg) => (
            <div key={msg.id} className={`flex ${msg.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
              <div className="max-w-[75%] space-y-1.5">
                <div className={`flex items-center gap-2 px-1 ${msg.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{msg.senderName || 'Authorized User'}</span>
                </div>
                <div className={`px-6 py-4 rounded-3xl text-[14px] font-medium shadow-sm border ${
                  msg.senderId === currentUser.id 
                    ? 'bg-slate-900 text-white border-slate-800 rounded-tr-none' 
                    : 'bg-white text-slate-700 border-slate-200 rounded-tl-none'
                }`}>
                  {msg.content}
                  <div className={`text-[10px] mt-2 opacity-40 ${msg.senderId === currentUser.id ? 'text-right' : 'text-left'}`}>
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        {/* Message Input */}
        <div className="p-7 bg-white border-t">
          <form onSubmit={handleSendMessage} className="flex gap-4">
            <input 
              type="text" 
              value={chatInput}
              onChange={e => setChatInput(e.target.value)}
              placeholder="Address the student's concern here..."
              className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-7 py-5 text-sm font-semibold focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all placeholder:text-slate-400"
            />
            <button 
              type="submit" 
              disabled={!chatInput.trim()} 
              className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-bold text-xs uppercase hover:bg-indigo-700 active:scale-95 transition-all shadow-xl shadow-indigo-100 disabled:opacity-50 disabled:shadow-none"
            >
              Dispatch
            </button>
          </form>
        </div>
      </div>

      {/* REASSIGNMENT / TRANSFER MODAL */}
      {showTransfer && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-indigo-950/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] w-full max-w-xl p-12 shadow-2xl border border-indigo-50/50 animate-in zoom-in-95 duration-200">
            <div className="flex items-center gap-4 mb-2">
               <div className="w-10 h-10 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
               </div>
               <h3 className="text-2xl font-black text-slate-900 tracking-tight">Transfer Grievance</h3>
            </div>
            <p className="text-sm font-medium text-slate-500 mb-10">Delegate this responsibility to a different institutional department or specialized staff member.</p>

            <div className="space-y-7">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Target Department</label>
                  <select 
                    value={transferDept}
                    onChange={e => setTransferDept(e.target.value as Department)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-indigo-500"
                  >
                    <option value="">Select Domain</option>
                    {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Designated Staff</label>
                  <select 
                    value={transferStaffId}
                    onChange={e => setTransferStaffId(e.target.value)}
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-indigo-500"
                  >
                    <option value="">Select Individual</option>
                    {staffList.filter(s => !transferDept || s.department === transferDept).map(s => (
                      <option key={s.id} value={s.id}>{s.name} ({s.id})</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Reason for Transfer</label>
                <textarea 
                  value={transferReason}
                  onChange={e => setTransferReason(e.target.value)}
                  placeholder="Explain why this case is being reassigned to another department..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-3xl px-6 py-5 text-sm font-semibold text-slate-900 outline-none focus:ring-2 focus:ring-indigo-500 h-32 resize-none transition-all"
                />
              </div>

              <div className="flex gap-4 pt-6">
                <button onClick={() => setShowTransfer(false)} className="flex-1 py-4.5 bg-slate-50 text-slate-500 font-bold rounded-2xl text-[11px] uppercase tracking-widest hover:bg-slate-100 transition-all">Dismiss</button>
                <button 
                  onClick={handleTransfer}
                  disabled={!transferDept || !transferStaffId || !transferReason}
                  className="flex-1 py-4.5 bg-indigo-600 text-white font-bold rounded-2xl text-[11px] uppercase tracking-widest shadow-2xl shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all disabled:opacity-50"
                >
                  Transfer
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagementConsole;

import React, { useState, useEffect, useRef } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { getGrievances, updateGrievance, getCurrentUser, sendMessage, getUserById, getAllStaff, transferGrievance } from '../store';
import { Grievance, Status, UserRole, Department, User } from '../types';
import { COLORS } from '../constants';
import { getStaffAssistance } from '../services/geminiService';

const ManagementConsole: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentUser = getCurrentUser();
  const [grievance, setGrievance] = useState<Grievance | null>(null);
  const [student, setStudent] = useState<User | null>(null);
  const [staffList, setStaffList] = useState<User[]>([]);
  const [chatInput, setChatInput] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [showTransfer, setShowTransfer] = useState(false);
  const [transferDept, setTransferDept] = useState<Department | ''>('');
  const [transferStaffId, setTransferStaffId] = useState('');
  const [transferReason, setTransferReason] = useState('');

  const chatEndRef = useRef<HTMLDivElement>(null);

  const refreshGrievance = async () => {
    const id = location.state?.grievanceId;
    if (id) {
      const all = await getGrievances();
      const g = all.find(x => x.id === id);
      if (g) {
        setGrievance(g);
        if (!g.isAnonymous) {
          const u = await getUserById(g.studentId);
          setStudent(u);
        }
      }
    }
  };

  useEffect(() => {
    refreshGrievance();
    getAllStaff().then(setStaffList);
    const interval = setInterval(refreshGrievance, 5000);
    return () => clearInterval(interval);
  }, [location.state]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [grievance?.conversation]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || !grievance) return;
    const res = await sendMessage(grievance.id, chatInput);
    if (res) {
      setGrievance(res);
      setChatInput('');
    }
  };

  const handleUpdateStatus = async (status: Status) => {
    if (!grievance || !currentUser) return;
    const now = Date.now();
    const updated = {
      ...grievance,
      status,
      lastStatusChange: now,
      history: [...grievance.history, { status, timestamp: now, userId: currentUser.id, remark: `Status updated to ${status}` }]
    };
    await updateGrievance(updated);
    setGrievance(updated);
  };

  const handleTransfer = async () => {
    if (!grievance || !transferDept || !transferStaffId || !transferReason) return;
    const res = await transferGrievance(grievance.id, transferDept as Department, transferStaffId, transferReason);
    if (res) {
      setGrievance(res);
      setShowTransfer(false);
      if (currentUser?.role === UserRole.STAFF && res.assignedToId !== currentUser.id) {
        navigate('/dashboard');
      }
    }
  };

  if (!grievance || !currentUser) return <div className="p-20 text-center text-slate-400 font-bold">Please select a case from your dashboard.</div>;

  return (
    <div className="flex flex-col xl:flex-row gap-6 h-[calc(100vh-160px)] animate-in fade-in duration-500 overflow-hidden">
      {/* SIDEBAR: Case Context */}
      <div className="xl:w-[380px] flex flex-col gap-5 overflow-y-auto custom-scrollbar pr-1">

        {/* Core Case Card */}
        <div className="bg-white rounded-[32px] border border-slate-200 p-6 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-black text-slate-900 text-lg tracking-tight">#{grievance.id}</h3>
            <span className={`${COLORS.status[grievance.status]} px-3 py-1 rounded-lg text-[10px] font-bold uppercase`}>{grievance.status}</span>
          </div>

          <div className="space-y-3 mb-6">
            <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sentiment</span>
              <div className="flex items-center gap-2">
                <div className={`w-2.5 h-2.5 rounded-full ${grievance.sentiment === 'Angry' || grievance.sentiment === 'Urgent' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]'}`}></div>
                <span className="text-xs font-bold text-slate-700">{grievance.sentiment || 'Evaluating'}</span>
              </div>
            </div>
            <div className="flex justify-between items-center p-4 bg-slate-50 rounded-2xl border border-slate-100">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Domain</span>
              <span className="text-xs font-bold text-slate-700">{grievance.department}</span>
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <div className="grid grid-cols-2 gap-3">
               <button onClick={() => handleUpdateStatus(Status.IN_PROGRESS)} className="py-3.5 bg-indigo-50 text-indigo-700 font-bold text-[11px] rounded-2xl uppercase hover:bg-indigo-100 transition-all active:scale-95">Accept Case</button>
               <button onClick={() => handleUpdateStatus(Status.RESOLVED)} className="py-3.5 bg-emerald-600 text-white font-bold text-[11px] rounded-2xl uppercase hover:bg-emerald-700 transition-all shadow-lg active:scale-95">Resolve</button>
            </div>
            <button onClick={() => setShowTransfer(true)} className="w-full py-3.5 bg-slate-100 text-slate-600 font-bold text-[11px] rounded-2xl uppercase hover:bg-slate-200 transition-all active:scale-95">Transfer Assignment</button>
          </div>
        </div>

        {/* Identity & Verification */}
        <div className="bg-white rounded-[32px] border border-slate-200 p-6 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Student Reporter</h4>
          {grievance.isAnonymous ? (
            <div className="flex items-center gap-4 p-2 bg-indigo-50/30 rounded-2xl border border-indigo-100/50">
              <div className="w-14 h-14 bg-white border border-indigo-100 rounded-2xl flex items-center justify-center text-indigo-300 shadow-sm">
                <svg className="w-7 h-7" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" /></svg>
              </div>
              <div>
                <p className="text-sm font-bold text-slate-900 mb-0.5">Anonymous Reporter</p>
                <p className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">Identity Protected</p>
              </div>
            </div>
          ) : student ? (
            <div className="flex items-center gap-4 p-2">
              <div className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center font-black text-xl shadow-xl shadow-indigo-100">
                {student.name[0]}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-bold text-slate-900 truncate leading-none mb-1">{student.name}</p>
                <p className="text-[10px] font-bold text-slate-400 truncate uppercase tracking-tight">{student.email}</p>
                <p className="text-[10px] font-bold text-indigo-500 mt-1 uppercase tracking-widest">Verified Profile</p>
              </div>
            </div>
          ) : <div className="p-4 text-center text-xs font-bold text-slate-300 animate-pulse">Loading identity...</div>}
        </div>

        {/* AI MEDIATOR TOOL: Staff Support */}
        <div className="bg-indigo-900 rounded-[32px] p-7 text-white shadow-xl shadow-indigo-900/10 flex flex-col gap-5">
          <div className="flex items-center justify-between">
             <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-indigo-500 rounded-xl flex items-center justify-center font-black text-[10px]">AI</div>
                <p className="text-[11px] font-black uppercase tracking-[0.2em]">Mediator Advice</p>
             </div>
             {isAiLoading && <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>}
          </div>

          <div className="min-h-[80px]">
            <p className="text-[12px] leading-relaxed text-indigo-100/80 font-medium italic">
              {aiResponse || 'Consult the mediator for resolution strategies and student communication drafts.'}
            </p>
          </div>

          <button 
            onClick={async () => {
                if (!grievance) return;
                setIsAiLoading(true);
                try {
                  const res = await getStaffAssistance(grievance.description, grievance.sentiment || 'Neutral');
                  setAiResponse(res || 'Mediator busy. Try again.');
                } catch (e) {
                  setAiResponse('AI Gateway Timeout.');
                } finally {
                  setIsAiLoading(false);
                }
            }} 
            disabled={isAiLoading}
            className="w-full py-3.5 bg-white text-indigo-900 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 active:scale-95 transition-all disabled:opacity-50 shadow-lg shadow-indigo-950/20"
          >
            Get Expert Support
          </button>
        </div>
      </div>

      {/* CHAT HUB: Direct Communication */}
      <div className="flex-1 flex flex-col bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden min-h-0">
        <div className="px-8 py-5 border-b flex items-center justify-between bg-white/80 backdrop-blur-md sticky top-0 z-10">
          <div className="flex items-center gap-4">
             <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_10px_rgba(16,185,129,0.6)]"></div>
             <div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Direct Chat Protocol</p>
               <p className="text-xs font-bold text-slate-700 mt-0.5">Secure channel with reporter</p>
             </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/5 custom-scrollbar">
          {/* Main Concern Anchor */}
          <div className="flex justify-center mb-10">
             <div className="max-w-[85%] bg-white border border-slate-100 p-8 rounded-[32px] shadow-sm relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-500"></div>
                <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-3">Institutional Complaint Anchor</p>
                <p className="text-[15px] font-semibold text-slate-800 leading-relaxed italic">"{grievance.description}"</p>
             </div>
          </div>

          {(grievance.conversation || []).map((msg) => (
            <div key={msg.id} className={`flex ${msg.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
              <div className="max-w-[75%] space-y-1.5">
                <div className={`flex items-center gap-2 px-1 ${msg.senderId === currentUser.id ? 'justify-end' : 'justify-start'}`}>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    {msg.senderId === currentUser.id ? 'Staff Response' : (grievance.isAnonymous ? 'Anonymous Student' : (msg.senderName || 'Student'))}
                  </span>
                </div>
                <div className={`px-6 py-4 rounded-3xl text-[14px] font-medium shadow-sm border ${
                  msg.senderId === currentUser.id 
                    ? 'bg-slate-900 text-white border-slate-800 rounded-tr-none' 
                    : 'bg-white text-slate-700 border-slate-200 rounded-tl-none'
                }`}>
                  {msg.content}
                  <div className={`text-[10px] mt-2 opacity-40 ${msg.senderId === currentUser.id ? 'text-right' : 'text-left'}`}>
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        <div className="p-7 bg-white border-t">
          <form onSubmit={handleSendMessage} className="flex gap-4">
            <input 
              type="text" 
              value={chatInput}
              onChange={e => setChatInput(e.target.value)}
              placeholder="Draft your message to the student..."
              className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-7 py-5 text-sm font-semibold focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
            />
            <button 
              type="submit" 
              disabled={!chatInput.trim()} 
              className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-bold text-xs uppercase hover:bg-indigo-700 active:scale-95 transition-all shadow-xl shadow-indigo-100 disabled:opacity-50"
            >
              Dispatch
            </button>
          </form>
        </div>
      </div>

      {/* TRANSFER MODAL */}
      {showTransfer && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-indigo-950/40 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] w-full max-w-xl p-12 shadow-2xl animate-in zoom-in-95 duration-200">
            <h3 className="text-2xl font-black text-slate-900 tracking-tight mb-2">Reassign Grievance</h3>
            <p className="text-sm font-medium text-slate-500 mb-10">Shift ownership to a specialized institutional division.</p>

            <div className="space-y-7">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Target Department</label>
                  <select value={transferDept} onChange={e => setTransferDept(e.target.value as Department)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold">
                    <option value="">Select Domain</option>
                    {Object.values(Department).map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1">Staff Member</label>
                  <select value={transferStaffId} onChange={e => setTransferStaffId(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 text-sm font-bold">
                    <option value="">Select Individual</option>
                    {staffList.filter(s => !transferDept || s.department === transferDept).map(s => (
                      <option key={s.id} value={s.id}>{s.name}</option>
                    ))}
                  </select>
                </div>
              </div>
              <textarea value={transferReason} onChange={e => setTransferReason(e.target.value)} placeholder="Reason for transfer..." className="w-full bg-slate-50 border border-slate-200 rounded-3xl px-6 py-5 text-sm font-semibold h-32 resize-none outline-none focus:ring-2 focus:ring-indigo-500" />
              <div className="flex gap-4">
                <button onClick={() => setShowTransfer(false)} className="flex-1 py-4.5 bg-slate-50 text-slate-500 font-bold rounded-2xl text-[11px] uppercase">Cancel</button>
                <button onClick={handleTransfer} disabled={!transferDept || !transferStaffId || !transferReason} className="flex-1 py-4.5 bg-indigo-600 text-white font-bold rounded-2xl text-[11px] uppercase">Transfer Now</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default ManagementConsole;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { getGrievances, getCurrentUser, sendMessage } from '../store';
import { Grievance, Status, Department } from '../types';
import { ICONS, COLORS } from '../constants';

const GrievanceTracker: React.FC = () => {
  const user = getCurrentUser();
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterCategory, setFilterCategory] = useState<string>('all');
  const [grievances, setGrievances] = useState<Grievance[]>([]);
  const [selectedGrievance, setSelectedGrievance] = useState<Grievance | null>(null);
  const [chatInput, setChatInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  const refreshData = async () => {
    const all = await getGrievances();
    setGrievances(all);
    if (selectedGrievance) {
        const updated = all.find(g => g.id === selectedGrievance.id);
        if (updated) setSelectedGrievance(updated);
    }
  };

  useEffect(() => {
    refreshData();
    const interval = setInterval(refreshData, 5000);
    return () => clearInterval(interval);
  }, [selectedGrievance?.id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [selectedGrievance?.conversation]);

  const complaints = useMemo(() => {
    if (!user) return [];
    return grievances.filter(g => g.studentId === user.id).filter(g => {
      const matchSearch = g.id.toLowerCase().includes(search.toLowerCase()) || (g.title || '').toLowerCase().includes(search.toLowerCase());
      const matchStatus = filterStatus === 'all' || g.status === filterStatus;
      const matchCategory = filterCategory === 'all' || g.department === filterCategory;
      return matchSearch && matchStatus && matchCategory;
    });
  }, [user, grievances, search, filterStatus, filterCategory]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || !selectedGrievance) return;
    const res = await sendMessage(selectedGrievance.id, chatInput);
    if (res) {
        setChatInput('');
        setSelectedGrievance(res);
    }
  };

  if (!user) return null;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Institutional Record</h2>
          <p className="text-sm font-medium text-slate-500 mt-1">Audit and interact with your personal grievance pipeline.</p>
        </div>
        <button onClick={() => navigate('/chatbot')} className="flex items-center gap-3 bg-indigo-600 text-white px-7 py-3 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100">
          <ICONS.Raise />
          New Filing
        </button>
      </div>

      {/* Table & Filters (Simplified for space) */}
      <div className="bg-white rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b">
              <tr>
                <th className="px-10 py-5">Case Reference</th>
                <th className="px-10 py-5">Summary</th>
                <th className="px-10 py-5">Status</th>
                <th className="px-10 py-5">Category</th>
                <th className="px-10 py-5 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {complaints.map(g => (
                <tr key={g.id} className="hover:bg-slate-50 transition-all cursor-pointer group" onClick={() => setSelectedGrievance(g)}>
                  <td className="px-10 py-6 font-black text-slate-900 text-sm">#{g.id}</td>
                  <td className="px-10 py-6 text-sm font-bold text-slate-700">{g.summary || 'Awaiting Analysis'}</td>
                  <td className="px-10 py-6"><span className={COLORS.status[g.status]}>{g.status}</span></td>
                  <td className="px-10 py-6"><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{g.department}</span></td>
                  <td className="px-10 py-6 text-right">
                    <button className="bg-indigo-50 text-indigo-600 px-5 py-2.5 rounded-xl font-black text-[9px] uppercase tracking-widest group-hover:bg-indigo-600 group-hover:text-white transition-all">Interact</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* RESOLUTION HUB MODAL (Direct Chat) */}
      {selectedGrievance && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/40 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[40px] w-full max-w-4xl h-[85vh] flex flex-col shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-200">
            {/* Header */}
            <div className="px-10 py-6 border-b flex items-center justify-between bg-white sticky top-0 z-10">
              <div className="flex items-center gap-4">
                 <div className="w-10 h-10 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 font-black">Ref</div>
                 <div>
                   <h3 className="text-xl font-black text-slate-900 tracking-tight">Case #{selectedGrievance.id}</h3>
                   <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">Direct Messaging Channel</p>
                 </div>
              </div>
              <button onClick={() => setSelectedGrievance(null)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            {/* Chat Flow */}
            <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-slate-50/10 custom-scrollbar">
              <div className="bg-indigo-50/50 border border-indigo-100/50 p-6 rounded-3xl mb-10">
                <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-2">Original Institutional Complaint</p>
                <p className="text-sm font-semibold text-slate-800 italic leading-relaxed">"{selectedGrievance.description}"</p>
              </div>

              {(selectedGrievance.conversation || []).map((msg) => (
                <div key={msg.id} className={`flex ${msg.senderId === user.id ? 'justify-end' : 'justify-start'}`}>
                  <div className="max-w-[75%]">
                    <p className={`text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 px-1 ${msg.senderId === user.id ? 'text-right' : 'text-left'}`}>
                      {msg.senderId === user.id ? 'You' : 'KIT Staff Authority'}
                    </p>
                    <div className={`px-6 py-4 rounded-3xl text-sm font-medium shadow-sm border ${
                      msg.senderId === user.id ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none' : 'bg-white text-slate-700 border-slate-200 rounded-tl-none'
                    }`}>
                      {msg.content}
                    </div>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef}></div>
            </div>

            {/* Input */}
            <div className="p-8 bg-white border-t">
              <form onSubmit={handleSendMessage} className="flex gap-4">
                <input 
                  type="text" 
                  value={chatInput} 
                  onChange={e => setChatInput(e.target.value)} 
                  placeholder="Draft your message back to the staff member..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-7 py-5 text-sm font-semibold focus:ring-2 focus:ring-indigo-600 outline-none"
                />
                <button type="submit" disabled={!chatInput.trim()} className="bg-slate-900 text-white px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 disabled:opacity-30 transition-all">Send</button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GrievanceTracker;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { getCurrentUser, logout, subscribeToSession } from '../store';
import { UserRole } from '../types';
import { ICONS } from '../constants';

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [currentUser, setUser] = useState(getCurrentUser());

  useEffect(() => {
    const cleanup = subscribeToSession(() => {
      setUser(getCurrentUser());
    });
    return cleanup;
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const isAuthPage = location.pathname === '/login' || location.pathname === '/';
  if (!currentUser || isAuthPage) return <>{children}</>;

  const navItems = [
    { path: '/dashboard', label: 'Dashboard', icon: <ICONS.Dashboard />, roles: [UserRole.STUDENT, UserRole.STAFF, UserRole.ADMIN] },
    { path: '/chatbot', label: 'Filing Assistant', icon: <ICONS.Chatbot />, roles: [UserRole.STUDENT] },
    { path: '/track', label: 'Case Tracker', icon: <ICONS.List />, roles: [UserRole.STUDENT] },
    { path: '/manage', label: 'Direct Worklist', icon: <ICONS.List />, roles: [UserRole.STAFF] },
    { path: '/analytics', label: 'Institutional Metrics', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2m0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>, roles: [UserRole.ADMIN] },
  ];

  const getInitials = (name: string) => {
    const parts = name.split(' ');
    if (parts.length > 1) return (parts[0][0] + parts[1][0]).toUpperCase();
    return name.slice(0, 2).toUpperCase();
  };

  return (
    <div className="min-h-screen flex bg-[#F8FAFC] text-slate-900 font-sans selection:bg-indigo-100">
      {/* Sidebar */}
      <aside className="w-[300px] bg-white border-r border-slate-200 flex flex-col fixed h-screen z-30 shadow-[10px_0_30px_rgba(0,0,0,0.015)]">
        <div className="p-10 pb-12 flex items-center gap-5">
          <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center p-2.5 shadow-sm border border-indigo-100/50">
            <img src="https://mental-orange-t56uiavvis-coyn24mp43.edgeone.app/logo_cropped.png" alt="KIT" className="h-full w-auto object-contain" />
          </div>
          <div className="min-w-0">
            <h1 className="text-lg font-black text-slate-900 leading-tight tracking-tighter">KIT HUB</h1>
            <p className="text-[10px] text-indigo-600 font-black uppercase tracking-[0.2em] mt-0.5">UGRS Portal</p>
          </div>
        </div>

        <nav className="flex-1 px-6 space-y-1.5 overflow-y-auto custom-scrollbar">
          {navItems.filter(item => item.roles.includes(currentUser.role)).map((item) => {
            const isActive = location.pathname === item.path || (item.path === '/manage' && location.pathname.startsWith('/manage'));
            return (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center gap-4 px-5 py-4 rounded-2xl text-[13px] font-bold transition-all group ${
                  isActive 
                    ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-200/50 translate-x-1' 
                    : 'text-slate-400 hover:bg-slate-50 hover:text-slate-900'
                }`}
              >
                <span className={`transition-colors ${isActive ? 'text-white' : 'text-slate-400 group-hover:text-indigo-500'}`}>{item.icon}</span>
                {item.label}
              </Link>
            );
          })}
        </nav>

        <div className="p-8 border-t border-slate-100 bg-slate-50/30">
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-4 px-5 py-4 text-xs font-black text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all uppercase tracking-widest"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3 3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            End Session
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 ml-[300px] flex flex-col min-h-screen">
        <header className="h-[96px] bg-white/80 backdrop-blur-md border-b border-slate-200 px-12 flex items-center justify-between sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <h2 className="text-xl font-black text-slate-900 tracking-tight">Access Control: {currentUser.name}</h2>
            <div className="h-5 w-[1px] bg-slate-200 mx-2"></div>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">{currentUser.role} Level Authority</p>
          </div>
          <div className="flex items-center gap-10">
            <button className="relative p-3 text-slate-400 hover:text-indigo-600 transition-all bg-slate-50 rounded-2xl border border-slate-100 shadow-sm">
              <ICONS.Notification />
              <span className="absolute -top-1 -right-1 w-5 h-5 bg-indigo-600 text-white text-[9px] flex items-center justify-center rounded-full border-2 border-white font-black">2</span>
            </button>
            <div className="flex items-center gap-5 pl-10 border-l border-slate-100">
              <div className="text-right">
                <span className="block text-xs font-black text-slate-900 uppercase tracking-tight">{currentUser.name}</span>
                <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{currentUser.department || 'General'}</span>
              </div>
              <div className="w-14 h-14 bg-slate-900 text-white rounded-2xl flex items-center justify-center text-sm font-black shadow-2xl border-2 border-white">
                {getInitials(currentUser.name)}
              </div>
            </div>
          </div>
        </header>

        <main className="p-12 max-w-[1600px] w-full flex-1 mx-auto">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;
